SELECT A.HOMEPAGE_ID, A.LARGE_CATEGORY_IDX, A.GROUP_IDX, A.CATEGORY_IDX, A.TERMS_IDX, A.ADD_DATE, A.ADD_ID, B.TITLE, (SELECT C.CODE_NAME FROM CMS_CODE C WHERE C.GROUP_ID = 'C0014' AND C.CODE_ID = B.TERMS_TYPE) AS TERMS_TYPE_NAME FROM CMS_TRAINING_CATEGORY_TERMS A left outer join CMS_TRAINING_TERMS B on A.TERMS_IDX = B.TERMS_IDX WHERE A.HOMEPAGE_ID = #{homepage_id} AND A.LARGE_CATEGORY_IDX = #{large_category_idx} AND A.GROUP_IDX = #{group_idx}
AND A.CATEGORY_IDX = #{category_idx}
AND B.DELETE_YN = 'N' AND B.USE_YN = 'Y' AND B.TITLE IS NOT NULL AND B.CONTENTS IS NOT NULL ORDER BY A.ADD_DATE ASC

SELECT
	COUNT(*)
FROM
	CMS_TRAINING_CATEGORY_TERMS A
	left outer join CMS_TRAINING_TERMS B on A.TERMS_IDX = B.TERMS_IDX
WHERE 			
	A.HOMEPAGE_ID = #{homepage_id}
	AND A.LARGE_CATEGORY_IDX = #{large_category_idx}
	AND A.GROUP_IDX = #{group_idx}

		AND A.CATEGORY_IDX = #{category_idx}


		AND A.TERMS_IDX = #{terms_idx}

	AND B.DELETE_YN = 'N'
	AND B.USE_YN = 'Y'
ORDER BY
	A.TERMS_IDX ASC

